SELECT DISTINCT gh.location_name
FROM DIM_GEOGRAPHY_HIERARCHY gh
WHERE EXISTS (
    SELECT 1 FROM FACT_HOUSING fh 
    WHERE gh.HIERARCHY_ID = fh.HIERARCHY_ID AND fh.NUMBER_OF_HOUSEHOLDS > 500
)
OR EXISTS (
    SELECT 1 FROM FACT_WORKERS_TERTIARY_SECTOR fwts 
    WHERE gh.HIERARCHY_ID = fwts.HIERARCHY_ID AND fwts.MALE_WORKERS_TRADE_COMMERCE > 10000
);

